#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int dfn[100010],low[100010],siz[100010],scc[100010],scccnt,dfncnt;
bool instk[100010];
stack<int> stk;
void tarjan(int x)
{
    stk.push(x);
    instk[x]=1;
    dfn[x]=low[x]=++dfncnt;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        int top;
        scccnt++;
        do
        {
            top=stk.top();
            stk.pop();
            scc[top]=scccnt;
            siz[scccnt]++;
            instk[top]=0;
        }while(top!=x);
    }
}
int in[100010],out[100010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x;
        while(scanf("%d",&x)==1&&x)
        {
            mp[i].push_back(x);
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j:mp[i])
        {
            if(scc[i]!=scc[j])
            {
                in[scc[j]]++;
                out[scc[i]]++;
            }
        }
    }
    int ans1=0,ans2=0;
    for(int i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            ans1++;
        }
        if(out[i]==0)
        {
            ans2++;
        }
    }
    if(scccnt==1)
    {
        printf("%d\n0",ans1);
        return 0;
    }
    printf("%d\n%d",ans1,max(ans1,ans2));
    return 0;
}
